// ---- 1. Gemini raw text nikalo (output shape vary karta hai) ----
const j = $json;
let raw = '';
if (j.content && j.content.parts) raw = j.content.parts.map(p => p.text).join('\n');
else if (Array.isArray(j.content)) raw = j.content.map(c => c.text || c).join('\n');
else if (typeof j.content === 'string') raw = j.content;
else if (j.text) raw = j.text;
raw = raw.trim().replace(/^```(json)?/i, '').replace(/```$/, '').trim();

const msg = $('Telegram Trigger').item.json.message;
const chatId = String(msg.chat.id);
const userName = [msg.from.first_name, msg.from.last_name].filter(Boolean).join(' ');
const fail = t => ({ json: { is_bill: false, text: t, chat_id: chatId } });

// ---- 2. JSON parse ----
let d;
try { d = JSON.parse(raw); } catch (e) { return fail('Sorry! Bill process karne mein dikkat aayi. 🙏 Kripya dobara photo bhejein.'); }
if (d.is_bill === false) return fail('Sorry! Yeh photo saaf nahi hai ya bill nahi lag rahi. 🙏 Kripya bill ki clear photo bhejein.');

// ---- 3. Deterministic math (AI ke bharose nahi) ----
const num = v => (typeof v === 'number' && isFinite(v)) ? v : (typeof v === 'string' && v.trim() !== '' && isFinite(Number(v)) ? Number(v) : null);
const show = v => (v === null || v === undefined || v === '') ? '—' : v;
const items = d.items || [];
let subtotal = 0, anyUnreadable = false;
const lines = items.map((it, i) => {
  const amt = num(it.amount), q = num(it.qty), r = num(it.rate);
  if (amt === null) anyUnreadable = true; else subtotal += amt;
  let line = (i + 1) + '. ' + show(it.name);
  if (q !== null && r !== null) {
    line += ' — ' + q + ' x ₹' + r + ' = ₹' + (amt === null ? '⚠ confirm' : amt);
    if (amt !== null && Math.abs(q * r - amt) > 0.01) line += ' ⚠ check';
  } else {
    line += ' — ₹' + (amt === null ? '⚠ confirm' : amt);
  }
  return line;
});

const discount = num(d.discount);
const paid = num(d.paid);
const stated = num(d.stated_total);
const expected = Math.round((subtotal - (discount || 0)) * 100) / 100;

let verify, verifLine;
if (anyUnreadable || stated === null) {
  verify = 'unverified';
  verifLine = '⚠ Kuch values saaf nahi the, total verify nahi ho paya.';
} else if (Math.abs(expected - stated) <= 0.01) {
  verify = 'match';
  verifLine = '✅ Total sahi hai (items ka jod' + (discount ? ' − chhoot' : '') + ' match karta hai)';
} else {
  verify = 'mismatch';
  verifLine = '⚠ MISMATCH: Bill pe likha ₹' + stated + ', hisaab se banta hai ₹' + expected + ' (farak ₹' + Math.round(Math.abs(stated - expected) * 100) / 100 + '). Kripya check karein.';
}
const balance = (paid !== null && stated !== null) ? Math.round((stated - paid) * 100) / 100 : null;

// ---- 4. Invoice text ----
const L = '━━━━━━━━━━━━━━━━━━';
const body = ['🧾 DIGITAL INVOICE', L,
  '🏪 Dukaan: ' + show(d.shop),
  '👤 Grahak: ' + show(d.customer),
  '📅 Tareekh: ' + show(d.date),
  '🔢 Bill No: ' + show(d.bill_no), L,
  'SAMAAN:', ...lines, L];
if (discount !== null || paid !== null) body.push('Jod (Subtotal): ₹' + subtotal);
if (discount !== null) body.push('Chhoot (Discount): − ₹' + discount);
body.push('💰 KUL TOTAL: ₹' + (stated === null ? '⚠ confirm' : stated));
if (paid !== null) body.push('Jama (Paid): ₹' + paid);
if (balance !== null) body.push('Baki (Balance): ₹' + balance);
body.push(verifLine, L);
let text = body.join('\n');
if (text.includes('⚠')) text += '\n⚠ wale values saaf nahi the — galat ho toh ✏️ dabayein.';
text += '\n\nSab sahi hai? Neeche button dabakar batayein 👇';

// ---- 5. Khata row + UID ----
const uid = Date.now().toString(36);
const ist = new Date(Date.now() + 19800000).toISOString().replace('T', ' ').slice(0, 19);
return { json: {
  is_bill: true, text: text, uid: uid,
  timestamp: ist, chat_id: chatId, user: userName,
  shop: show(d.shop), customer: show(d.customer),
  bill_date: show(d.date), bill_no: show(d.bill_no),
  items_json: JSON.stringify(items),
  subtotal: String(subtotal),
  discount: discount === null ? '' : String(discount),
  total: stated === null ? String(d.stated_total || '') : String(stated),
  paid: paid === null ? '' : String(paid),
  balance: balance === null ? '' : String(balance),
  verify: verify, confirm: '⏳ Pending',
} };

const d = $json;
const esc = s => String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const items = JSON.parse(d.items_json || '[]');
const rows = items.map((it, i) => {
  const q = (it.qty === null || it.qty === undefined) ? '-' : it.qty;
  const r = (it.rate === null || it.rate === undefined) ? '-' : it.rate;
  const a = (it.amount === null || it.amount === undefined) ? '-' : it.amount;
  return '<tr><td>' + (i + 1) + '</td><td>' + esc(it.name) + '</td><td class="c">' + esc(q) + '</td><td class="r">' + esc(r) + '</td><td class="r">' + esc(a) + '</td></tr>';
}).join('');

let totals = '';
if (d.discount !== '' || d.paid !== '') totals += '<tr><td>Jod (Subtotal)</td><td class="r">₹' + esc(d.subtotal) + '</td></tr>';
if (d.discount !== '') totals += '<tr><td>Chhoot (Discount)</td><td class="r">- ₹' + esc(d.discount) + '</td></tr>';
totals += '<tr class="big"><td>Kul Total</td><td class="r">₹' + esc(d.total) + '</td></tr>';
if (d.paid !== '') totals += '<tr><td>Jama (Paid)</td><td class="r">₹' + esc(d.paid) + '</td></tr>';
if (d.balance !== '') totals += '<tr class="big"><td>Baki (Balance)</td><td class="r">₹' + esc(d.balance) + '</td></tr>';

let note = '';
if (d.verify === 'match') note = '<p class="ok">✓ Total verified — items ka jod match karta hai</p>';
else if (d.verify === 'mismatch') note = '<p class="warn">⚠ MISMATCH — bill ka total items ke jod se alag hai. Kripya check karein.</p>';
else note = '<p class="warn">⚠ Kuch values saaf nahi the (⚠ confirm) — verify pending.</p>';

const html = '<!DOCTYPE html><html><head><meta charset="utf-8"><style>' +
  'body{font-family:Helvetica,Arial,sans-serif;color:#222;margin:32px;font-size:13px}' +
  'h1{font-size:20px;margin:0}' +
  '.head{border-bottom:2px solid #222;padding-bottom:8px;margin-bottom:12px}' +
  '.meta{width:100%;margin-bottom:14px}.meta td{padding:2px 0}' +
  'table.items{width:100%;border-collapse:collapse;margin-bottom:14px}' +
  'table.items th{background:#f0efe8;text-align:left;padding:6px;border:1px solid #ccc}' +
  'table.items td{padding:6px;border:1px solid #ccc}' +
  '.c{text-align:center}.r{text-align:right}' +
  'table.tot{width:45%;margin-left:auto;border-collapse:collapse}table.tot td{padding:4px 6px}' +
  '.big td{font-weight:bold;font-size:15px;border-top:1px solid #222}' +
  '.ok{color:#1a7a1a}.warn{color:#b00020;font-weight:bold}' +
  '.foot{margin-top:24px;font-size:11px;color:#777;border-top:1px solid #ccc;padding-top:6px}' +
  '</style></head><body>' +
  '<div class="head"><h1>' + esc(d.shop === '—' ? 'Digital Invoice' : d.shop) + '</h1><div>Digital Invoice</div></div>' +
  '<table class="meta"><tr><td><b>Grahak:</b> ' + esc(d.customer) + '</td><td><b>Bill No:</b> ' + esc(d.bill_no) + '</td></tr>' +
  '<tr><td><b>Tareekh:</b> ' + esc(d.bill_date) + '</td><td><b>Generated:</b> ' + esc(d.timestamp) + '</td></tr></table>' +
  '<table class="items"><tr><th>#</th><th>Samaan</th><th>Qty</th><th>Rate (₹)</th><th>Amount (₹)</th></tr>' + rows + '</table>' +
  '<table class="tot">' + totals + '</table>' + note +
  '<div class="foot">Yeh invoice kacche bill ki photo se automatically banaya gaya hai · UID: ' + esc(d.uid) + '</div>' +
  '</body></html>';

return { json: Object.assign({}, d, { html: html }) };
